import java.util.stream.IntStream;

public class PrimeNumber {
    public static boolean isPrime(int n) {
        return n > 1 && IntStream.rangeClosed(2, (int) Math.sqrt(n))
                 .noneMatch(i -> n % i == 0);
    }
}
